def get_median(arr1, arr2, n):
    if n == 0:
        return None

    left = right = -float('inf')
    lmax1 = lmax2 = rmin1 = rmin2 = float('inf')

    low, high = 0, n
    while low <= high:
        i = (low + high) // 2
        j = (n + 1) // 2 - i

        if i < n and arr2[j-1] > arr1[i]:
            left = arr2[j-1]
            lmax1 = max(lmax1, arr1[i])
            low = i + 1
        elif i > 0 and arr1[i-1] > arr2[j]:
            right = arr1[i-1]
            rmin2 = min(rmin2, arr2[j])
            high = i - 1
        else:
            if i == 0: 
                lmax1 = rmin1 = arr1[0]
            elif j == 0: 
                lmax2 = rmin2 = arr2[0]
            else: 
                lmax1 = max(arr1[i-1], arr2[j-1])
                lmax2 = max(lmax1, min(arr1[i] if i < n else float('inf'), arr2[j] if j < n else float('inf')))

            rmin1 = min(arr1[i] if i < n else float('inf'), arr2[j] if j < n else float('inf'))
            rmin2 = min(rmin1, max(arr1[i-1] if i > 0 else -float('inf'), arr2[j-1] if j > 0 else -float('inf')))

            break

    return (max(left, right) + lmax2) / 2.0

