def remove_parenthesis(input_string):
    result = ""
    stack = []

    for char in input_string:
        if char == '(':
            stack.append(char)
        elif char == ')':
            if stack:
                stack.pop()
            continue
        result += char

    return "".join([char for char in result if char not in '()'])

