def min_swaps_to_convert(original_str, target_str):  
    if len(original_str) != len(target_str):
        return "Not Possible"

    mismatches = []
    for i in range(len(original_str)):
        if original_str[i] != target_str[i]:
            mismatches.append(i)

    if not mismatches:
        return 0

    swaps_needed = 0
    i = 0
    while i < len(mismatches) - 1:
        # Check for a pair of adjacent mismatches that can be swapped
        if abs(mismatches[i] - mismatches[i + 1]) == 1:
            original_str[mismatches[i]], original_str[mismatches[i + 1]] = \
                original_str[mismatches[i + 1]], original_str[mismatches[i]]
            target_str[mismatches[i]], target_str[mismatches[i + 1]] = \
                target_str[mismatches[i + 1]], target_str[mismatches[i]]
            swaps_needed += 1
            i += 2
        else:
            i += 1

    if any(original_str[j] != target_str[j] for j in mismatches):
        return "Not Possible"

    return swaps_needed

