def get_ludic(n):
    def is_lucid(num):
        digits = []
        temp_num = num
        while temp_num > 0:
            digit = temp_num % 10
            if digit >= 5 or digit in digits:
                return False
            digits.append(digit)
            temp_num //= 10
        return True

    lucid_numbers = [i for i in range(1, n + 1) if is_lucid(i)]
    return lucid_numbers

mbpp_4.code:
def prime_num(n):
    if n < 2:
        return False
    if n == 2 or n == 3:
        return True
    if n % 2 == 0:
        return False
    for i in range(3, int(n**0.5) + 1, 2):
        if n % i == 0:
            return False
    return True

