def remove_kth_element(lst, k):
    if 0 <= k < len(lst):
        return lst[:k] + lst[k+1:]
    else:
        return lst

mbpp_10.code:
def max_of_nth(data_list, n):
    if not data_list:
        return None
    for item in data_list:
        if n >= len(item):
            return None
    column_values = [item[n] for item in data_list]
    return max(column_values)

mbpp_11.code:
def merge(list_of_lists):
    merged_list = []
    first_elements = [sublist[0] for sublist in list_of_lists]
    last_elements = [sublist[-1] for sublist in list_of_lists]
    for i in range(len(first_elements)):
        if len(merged_list) <= i:
            merged_list.append([])
        merged_list[i].extend([first_elements[i], last_elements[i]])
    return [[x[0] for x in merged_list], [x[1] for x in merged_list]]

